	@Test
	public void joinCommutePreservesIndependentInputsAndDeniesDirectionalInputs() throws Exception {
		StatementPattern left = pattern("shared", "leftOnly");
		StatementPattern right = pattern("shared", "rightOnly");
		QueryRoot safeRoot = new QueryRoot(new Join(left, right));
		assertThat(rewrite(safeRoot, "commuteJoin", safeRoot.getArg())).isTrue();
		Join swapped = (Join) safeRoot.getArg();
		assertThat(swapped.getLeftArg().getBindingNames()).contains("rightOnly");
		assertThat(swapped.getRightArg().getBindingNames()).contains("leftOnly");

		StatementPattern provider = pattern("shared", "provided");
		Filter dependent = new Filter(pattern("shared", "rightOnly"), Var.of("provided"));
		Join directional = new Join(provider, dependent);
		QueryRoot deniedRoot = new QueryRoot(directional);
		assertThat(rewrite(deniedRoot, "commuteJoin", directional)).isFalse();
		assertThat(deniedRoot.getArg()).isSameAs(directional);
	}

