	@Test
	public void parsedTransparentFlatteningRemapsIntoTheParentFrameWithoutDiscardingTheSeed() {
		ParsedTupleQuery parsed = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL,
				"SELECT ?x WHERE { { SELECT ?x WHERE { VALUES ?x { 1 } } } }", null);
		QueryRoot root = (QueryRoot) parsed.getTupleExpr();
		List<Projection> projections = new ArrayList<>();
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Projection projection) {
				projections.add(projection);
				super.meet(projection);
			}
		});
		Projection subquery = projections.stream().filter(Projection::isSubquery).findFirst().orElseThrow();
		ScopeSafeRewriter rewriter = new ScopeSafeRewriter(root);
		int decision = ScopeRewriteGuard.create(rewriter.analysis()).transparentSubquery(subquery);
		assertThat(decision)
				.as("guard=%s projection=%s childScope=%s outputScope=%s",
						decision == 0 ? "ACCEPT" : RejectReason.values()[decision - 1], subquery,
						rewriter.analysis().names(SemanticMask.SCOPE_OUT, subquery.getArg()),
						rewriter.analysis().names(SemanticMask.SCOPE_OUT, subquery))
				.isZero();

		boolean flattened = rewriter.flattenTransparentSubquery(subquery);
		assertThat(flattened).as("transaction=%s", rewriter.lastRejection()).isTrue();
		assertThat(rewriter.analysis().usesParserSeed()).isTrue();
		assertThat(rewriter.analysis().names(SemanticMask.SCOPE_OUT, root)).containsExactly("x");
	}

	private static boolean rewrite(QueryRoot root, String methodName, QueryModelNode boundary) throws Exception {
		ScopeSafeRewriter rewriter = new ScopeSafeRewriter(root);
		Method method = ScopeSafeRewriter.class.getDeclaredMethod(methodName, boundary.getClass());
		method.setAccessible(true);
		boolean rewritten = (boolean) method.invoke(rewriter, boundary);
		if (!rewritten && rewriter.lastRejection() != null) {
			System.err.println(methodName + " transaction rejection: " + rewriter.lastRejection());
		}
		return rewritten;
	}

	private static Projection projection(TupleExpr arg, boolean subquery, ProjectionElem... elements) {
		Projection projection = new Projection(arg, new ProjectionElemList(elements));
		projection.setSubquery(subquery);
		return projection;
	}

	private static Extension unknownExtension(String input) {
		return new Extension(pattern(input, "effectInput"),
				new ExtensionElem(new FunctionCall("urn:unknown:scope-safety"), "effect"));
	}

	private static StatementPattern pattern(String first, String second) {
		return new StatementPattern(Var.of(first),
				Var.of("_p", SimpleValueFactory.getInstance().createIRI("urn:p")), Var.of(second));
	}
